INSERT INTO `chat_faqs` (`id`, `keywords_pt`, `keywords_es`, `keywords_en`, `answer_pt`, `answer_es`, `answer_en`, `support_url`, `support_label`, `role_filter`, `priority`, `is_active`, `created_by_id`, `created_at`, `updated_at`) VALUES (1,'plano formacao inscricao','plan formacion inscripcion','training plan enrollment','Para se inscrever num plano de formacao, aceda a \'Planos de Formacao\' e clique em \'Inscrever-se\'.','Para inscribirse en un plan de formacion, acceda a \'Planes de Formacion\' y haga clic en \'Inscribirse\'.','To enroll in a training plan, go to \'Training Plans\' and click \'Enroll\'.',NULL,NULL,NULL,10,1,1,'2026-03-20 23:29:54',NULL),(2,'erro tutoria reportar','error tutoria reportar','tutoring error report','Para reportar um erro de tutoria, va a \'Tutoria > Erros\' e clique \'Novo Erro\'.','Para reportar un error de tutoria, vaya a \'Tutoria > Errores\' y haga clic en \'Nuevo Error\'.','To report a tutoring error, go to \'Tutoring > Errors\' and click \'New Error\'.',NULL,NULL,NULL,8,1,1,'2026-03-20 23:29:54',NULL),(3,'certificado download descarregar','certificado descarga descargar','certificate download','Os certificados ficam disponiveis apos a conclusao de um plano. Aceda a \'Os Meus Certificados\'.','Los certificados estan disponibles tras completar un plan. Acceda a \'Mis Certificados\'.','Certificates are available after completing a training plan. Go to \'My Certificates\'.',NULL,NULL,NULL,7,1,1,'2026-03-20 23:29:54',NULL),(4,'chamado ticket suporte','ticket soporte ayuda','ticket support help','Para abrir um chamado, aceda a \'Chamados\' e clique \'Novo Chamado\'.','Para abrir un ticket, acceda a \'Tickets\' y haga clic en \'Nuevo Ticket\'.','To open a support ticket, go to \'Tickets\' and click \'New Ticket\'.',NULL,NULL,NULL,6,1,1,'2026-03-20 23:29:54',NULL);
